PY
",
      "duration": 1.0
    },
    {
      "keystrokes": "python3 - <<'PY'
import json, pathlib
REQ_CASE_KEYS={'name','ok','steps','heap_sig','fl_count','fl_sig','byte_total','ledger'}
REQ_STEP_KEYS={'op','heap_sig','fl_count','fl_sig','byte_total'}
root=pathlib.Path('/app/output')
obj=json.loads((root/'alloc-audit.json').read_text())
errs=[]
for case in obj.get('cases',[]):
    missing=REQ_CASE_KEYS-set(case.keys())
    if missing:
        errs.append((case.get('name'),f'missing case keys {sorted(missing)}'))
        continue
    ledger_path=root/case['ledger'] if not str(case['ledger']).startswith('/') else pathlib.Path(case['ledger'])
    if not ledger_path.exists():
        errs.append((case['name'],f'ledger missing {ledger_path}'))
        continue
    steps=case['steps']
    ledger_lines=ledger_path.read_text().splitlines()
    if len(steps)!=len(ledger_lines):
        errs.append((case['name'],f'steps ({len(steps)}) != ledger lines ({len(ledger_lines)})'))
    # check step keys and that ledger row surfaces match step surfaces
    for i,s in enumerate(steps):
        m=REQ_STEP_KEYS-set(s.keys())
        if m:
            errs.append((case['name'],f'step {i} missing keys {sorted(m)}'))
            break
        try:
            row=json.loads(ledger_lines[i])
        except Exception as e:
            errs.append((case['name'],f'bad ledger json line {i}: {e}'))
            break
        for k in ['heap_sig','fl_count','fl_sig','byte_total']:
            if row.get(k)!=s.get(k):
                errs.append((case['name'],f'mismatch at step {i} field {k}: step={s.get(k)} ledger={row.get(k)}'))
                break
        else:
            continue
        break
    # final step should match case summary surfaces
    if steps:
        last=steps[-1]
        for k in ['heap_sig','fl_count','fl_sig','byte_total']:
            if last.get(k)!=case.get(k):
                errs.append((case['name'],f'case summary {k} != last step: case={case.get(k)} last={last.get(k)}'))
                break
print('errors',len(errs))
for e in errs[:50]:
    print('ERR',e[0],e[1])
